class Solution {
public:
    vector<int> validSequence(string word1, string word2) {
        int m = word1.size(), n = word2.size();
        vector<int> res;
        for (int i = 0; i < n; ++i) {
            if (word1[i] != word2[i]) {
                res.push_back(i);
            }
        }
        if (res.size() > 1) {
            for (int i = 0; i < res.size(); ++i) {
                if (word1[res[i]] != word2[res[i]]) {
                    bool found = false;
                    for (int j = res[i] + 1; j < m; ++j) {
                        if (word1[j] == word2[res[i]]) {
                            swap(res[i], res[j]);
                            found = true;
                            break;
                        }
                    }
                    if (!found) return {};
                }
            }
        } else if (res.size() == 1) {
            bool found = false;
            for (int j = 0; j < m; ++j) {
                if (word1[j] == word2[res[0]]) {
                    if (j < res[0]) {
                        res[0] = j;
                        found = true;
                        break;
                    }
                }
            }
            if (!found) return {};
        } else {
            int diff = 0;
            for (int i = 0; i < m; ++i) {
                if (word1[i] != word2[i]) ++diff;
                if (diff > 1) return {};
            }
            if (diff == 1) return {};
            res = vector<int>(n, 0);
            for (int i = 0; i < n; ++i) res[i] = i;
        }
        return res;
    }
};
